import{_ as t,a as e,b as o,c as i,d as r}from"./chunks/编辑配置.T0puvWjh.js";import{_ as n,o as d,c as l,a2 as s}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"Dodawanie kanału Telegram","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/upload/telegram.md","filePath":"pl-PL/upload/telegram.md","lastUpdated":1781962217000}'),p={name:"pl-PL/upload/telegram.md"};function c(z,a,k,h,w,b){return d(),l("div",null,[...a[0]||(a[0]=[s('<h1 id="dodawanie-kanału-telegram" tabindex="-1">Dodawanie kanału Telegram <a class="header-anchor" href="#dodawanie-kanału-telegram" aria-label="Permalink to &quot;Dodawanie kanału Telegram&quot;">​</a></h1><h2 id="co-przygotowac-przed-rozpoczeciem" tabindex="-1">Co przygotować przed rozpoczęciem <a class="header-anchor" href="#co-przygotowac-przed-rozpoczeciem" aria-label="Permalink to &quot;Co przygotować przed rozpoczęciem&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Wymaganie</th><th>Cel</th></tr></thead><tbody><tr><td>Konto Telegram</td><td>Do utworzenia bota i kanału przechowywania.</td></tr><tr><td><code>@BotFather</code></td><td>Do utworzenia bota Telegram.</td></tr><tr><td>Kanał Telegram</td><td>Docelowe miejsce przechowywania plików.</td></tr><tr><td><code>@userinfobot</code></td><td>Do sprawdzenia <code>Chat ID</code> kanału.</td></tr></tbody></table><h2 id="gdzie-dodac-kanał" tabindex="-1">Gdzie dodać kanał <a class="header-anchor" href="#gdzie-dodac-kanał" aria-label="Permalink to &quot;Gdzie dodać kanał&quot;">​</a></h2><ol><li>Otwórz Ustawienia systemowe.</li><li>Przejdź do Ustawień przesyłania.</li><li>Kliknij Dodaj kanał w prawym górnym rogu.</li><li>Wybierz <code>Telegram</code>.</li></ol><h2 id="opis-pol" tabindex="-1">Opis pól <a class="header-anchor" href="#opis-pol" aria-label="Permalink to &quot;Opis pól&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pole</th><th>Działanie</th><th>Wymagane</th></tr></thead><tbody><tr><td>Nazwa kanału</td><td>Czytelna nazwa, np. <code>Telegram Primary</code>.</td><td>Tak</td></tr><tr><td>Aktywny</td><td>Włącza lub wyłącza kanał.</td><td>Zalecane</td></tr><tr><td>Bot Token</td><td>Token bota Telegram.</td><td>Tak</td></tr><tr><td>Session ID (Chat ID)</td><td>ID kanału Telegram.</td><td>Tak</td></tr><tr><td>Relay Proxy URL (opcjonalnie)</td><td>Używaj tylko, gdy dostęp do Telegram jest niestabilny. Wpisz pełny URL proxy z <code>https://</code>.</td><td>Nie</td></tr><tr><td>Uwaga</td><td>Notatki do późniejszego utrzymania.</td><td>Nie</td></tr></tbody></table><h2 id="kroki-konfiguracji" tabindex="-1">Kroki konfiguracji <a class="header-anchor" href="#kroki-konfiguracji" aria-label="Permalink to &quot;Kroki konfiguracji&quot;">​</a></h2><h3 id="_1-utworz-bota-telegram" tabindex="-1">1. Utwórz bota Telegram <a class="header-anchor" href="#_1-utworz-bota-telegram" aria-label="Permalink to &quot;1. Utwórz bota Telegram&quot;">​</a></h3><ol><li>Otwórz Telegram i wyszukaj <code>@BotFather</code>.</li><li>Otwórz czat i kliknij <code>Start</code>.</li><li>Wyślij <code>/newbot</code>.</li><li>Postępuj zgodnie z instrukcjami i wpisz nazwę wyświetlaną bota.</li><li>Następnie wpisz nazwę użytkownika bota. Zwykle musi kończyć się na <code>bot</code>.</li><li>Po utworzeniu <code>@BotFather</code> zwróci token bota.</li></ol><p>Ten token wpisujesz w ImgBed jako <code>Bot Token</code>.</p><p><img src="'+t+'" alt="Zapisz token bota" loading="lazy"></p><h3 id="_2-utworz-kanał" tabindex="-1">2. Utwórz kanał <a class="header-anchor" href="#_2-utworz-kanał" aria-label="Permalink to &quot;2. Utwórz kanał&quot;">​</a></h3><ol><li>W Telegram kliknij Nowy kanał.</li><li>Wpisz nazwę kanału.</li><li>Dokończ tworzenie kanału.</li></ol><p>Możesz użyć kanału publicznego lub prywatnego.</p><p><img src="'+e+'" alt="Utwórz kanał" loading="lazy"></p><h3 id="_3-dodaj-bota-do-kanału" tabindex="-1">3. Dodaj bota do kanału <a class="header-anchor" href="#_3-dodaj-bota-do-kanału" aria-label="Permalink to &quot;3. Dodaj bota do kanału&quot;">​</a></h3><ol><li>Otwórz utworzony kanał.</li><li>Otwórz ustawienia kanału.</li><li>Dodaj członka lub administratora.</li><li>Wyszukaj nazwę użytkownika utworzonego bota.</li><li>Dodaj bota do kanału.</li></ol><p>Dla najbardziej niezawodnych uploadów nadaj botowi uprawnienia administratora.</p><p><img src="'+o+'" alt="Zaproś bota do kanału" loading="lazy"></p><h3 id="_4-pobierz-channel-id-przez-user-info-get-id-idbot" tabindex="-1">4. Pobierz Channel ID przez User Info - Get ID - IDbot <a class="header-anchor" href="#_4-pobierz-channel-id-przez-user-info-get-id-idbot" aria-label="Permalink to &quot;4. Pobierz Channel ID przez User Info - Get ID - IDbot&quot;">​</a></h3><ol><li>Wyszukaj w Telegram <code>@userinfobot</code>. Jego nazwa wyświetlana to zwykle <code>User Info - Get ID - IDbot</code>.</li><li>Otwórz czat i kliknij <code>Start</code>.</li><li>Wybierz <code>Channel</code> z opcji bota.</li><li>W selektorze wiadomości wybierz kanał docelowy i wyślij go do <code>@userinfobot</code>.</li><li>Gdy <code>@userinfobot</code> zwróci wynik, skopiuj numer przy <code>Id: -100...</code>.</li></ol><p>Numer zaczynający się od <code>-100</code> to <code>Session ID (Chat ID)</code> wymagane przez ImgBed.</p><p><img src="'+i+'" alt="Pobierz Channel ID" loading="lazy"></p><h3 id="_5-wypełnij-kanał-telegram-w-imgbed" tabindex="-1">5. Wypełnij kanał Telegram w ImgBed <a class="header-anchor" href="#_5-wypełnij-kanał-telegram-w-imgbed" aria-label="Permalink to &quot;5. Wypełnij kanał Telegram w ImgBed&quot;">​</a></h3><p>Wróć do okna konfiguracji i wypełnij:</p><table tabindex="0"><thead><tr><th>Pole UI</th><th>Wartość</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>Własna nazwa kanału, np. <code>TelegramPrimary</code>.</td></tr><tr><td>Aktywny</td><td>Zalecane.</td></tr><tr><td>Bot Token</td><td>Token od <code>@BotFather</code>.</td></tr><tr><td>Session ID (Chat ID)</td><td>Numer <code>-100...</code> zwrócony przez <code>@userinfobot</code>.</td></tr><tr><td>Relay Proxy URL (opcjonalnie)</td><td>Tylko gdy potrzeba, np. <code>https://your-tg-proxy.example.com</code>.</td></tr><tr><td>Uwaga</td><td>Opcjonalne notatki.</td></tr></tbody></table><p>Po zakończeniu kliknij Zapisz.</p><p><img src="'+r+`" alt="Edycja konfiguracji" loading="lazy"></p><h2 id="jak-sprawdzic" tabindex="-1">Jak sprawdzić <a class="header-anchor" href="#jak-sprawdzic" aria-label="Permalink to &quot;Jak sprawdzić&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Kontrola</th><th>Jak sprawdzić</th></tr></thead><tbody><tr><td>Karta kanału jest widoczna</td><td>Po zapisaniu w Ustawieniach przesyłania powinna pojawić się karta Telegram.</td></tr><tr><td>Kanał można włączyć</td><td>Przełącznik Aktywny pozostaje włączony.</td></tr><tr><td>Konfiguracja jest zapisana</td><td>Widok szczegółów pokazuje zapisany Bot Token i Chat ID.</td></tr><tr><td>Upload działa</td><td>Prześlij obraz testowy i sprawdź, czy pojawił się w docelowym kanale Telegram.</td></tr></tbody></table><h2 id="szybka-lista" tabindex="-1">Szybka lista <a class="header-anchor" href="#szybka-lista" aria-label="Permalink to &quot;Szybka lista&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Utwórz bota przez @BotFather</span></span>
<span class="line"><span>-&gt; Zapisz Bot Token</span></span>
<span class="line"><span>-&gt; Utwórz kanał Telegram</span></span>
<span class="line"><span>-&gt; Dodaj bota do kanału i nadaj uprawnienia administratora</span></span>
<span class="line"><span>-&gt; Wyszukaj @userinfobot i wybierz Channel</span></span>
<span class="line"><span>-&gt; Przekaż dowolną wiadomość z kanału do @userinfobot</span></span>
<span class="line"><span>-&gt; Skopiuj zwrócone Id: -100...</span></span>
<span class="line"><span>-&gt; Wpisz Bot Token i Chat ID w ImgBed</span></span>
<span class="line"><span>-&gt; Zapisz i prześlij obraz testowy</span></span></code></pre></div><h2 id="referencje" tabindex="-1">Referencje <a class="header-anchor" href="#referencje" aria-label="Permalink to &quot;Referencje&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const y=n(p,[["render",c]]);export{m as __pageData,y as default};
